class Symphony:
    def __init__(self):
        self.monitors = []
        self.status = 'idle'

    def register_monitor(self, plugin):
        self.monitors.append(plugin)

    def run_symphony(self, task, mode='auto'):
        self.status = 'running'
        for plugin in self.monitors:
            plugin.on_start(task)
        try:
            # Task execution logic
            task.run(mode)
            self.status = 'completed'
            for plugin in self.monitors:
                plugin.on_end(task)
        except Exception as e:
            self.status = 'error'
            for plugin in self.monitors:
                plugin.on_error(task, e)

    def get_status(self):
        return self.status
